"use client";

/**
 * Week-view calendar / scheduler — cold-start build on @gunjo/ui@0.0.1-alpha.2.
 *
 * THE HEADLINE GAP: @gunjo/ui ships NO calendar-view / scheduler / time-grid /
 * event-block / now-line primitive. `Calendar` is a react-day-picker date PICKER.
 * So the entire week VIEW — time axis, 7-day grid, all-day lane, absolutely
 * positioned event blocks, overlap column-packing, and the "now" indicator — is
 * hand-rolled here with plain divs + Tailwind. The library only contributes
 * primitives: Card, Popover, Dialog, Button, Badge, ToggleGroup, ScrollArea,
 * Select, Separator, Tooltip(Provider), Icon, and the bg/text/border tone tokens
 * used for category colors.
 *
 * Tailwind v4 dynamic-class caveat: category color classes are stored as full
 * literal strings in CATEGORY_STYLES (NOT built via `bg-${tone}-subtle`) so the
 * JIT scanner sees every class verbatim and does not tree-shake them.
 *
 * Hydration: the "now" line + "today" detection depend on `new Date()`, which
 * differs server vs client. They are gated behind a `mounted` flag so the first
 * client render matches the server (no now-line, no today highlight) and they
 * appear only after mount. No hydration mismatch.
 */

import * as React from "react";
import {
  Button,
  Badge,
  Card,
  Calendar,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  Popover,
  PopoverAnchor,
  PopoverContent,
  ScrollArea,
  Select,
  Separator,
  ToggleGroup,
  ToggleGroupItem,
  TooltipProvider,
  Icon,
} from "@gunjo/ui";
import {
  IconChevronLeft,
  IconChevronRight,
  IconPlus,
  IconClock,
  IconMapPin,
  IconCalendarEvent,
} from "@tabler/icons-react";

/* ------------------------------------------------------------------ */
/* Domain model                                                        */
/* ------------------------------------------------------------------ */

type Category = "work" | "personal" | "focus" | "health" | "social";

type CalEvent = {
  id: string;
  title: string;
  /** 0 = Monday … 6 = Sunday, relative to the visible week's Monday. */
  dayOffset: number;
  /** Minutes from midnight. Ignored for all-day events. */
  start: number;
  end: number;
  allDay?: boolean;
  category: Category;
  location?: string;
};

/**
 * Category visuals. Full literal class strings (no template interpolation) so
 * Tailwind v4's JIT keeps every utility. Each tone is one of @gunjo/ui's
 * semantic token families (primary/info/success/warning/destructive) — the only
 * category-color primitive the DS offers, since Badge has no semantic variants.
 */
const CATEGORY_STYLES: Record<
  Category,
  { label: string; block: string; dot: string; swatch: string }
> = {
  work: {
    label: "仕事",
    block:
      "bg-info-subtle text-info-subtle-foreground border-info-border hover:bg-info-subtle/80",
    dot: "bg-info",
    swatch: "bg-info-subtle border-info-border",
  },
  personal: {
    label: "プライベート",
    block:
      "bg-primary-subtle text-primary-subtle-foreground border-primary-border hover:bg-primary-subtle/80",
    dot: "bg-primary",
    swatch: "bg-primary-subtle border-primary-border",
  },
  focus: {
    label: "集中作業",
    block:
      "bg-warning-subtle text-warning-subtle-foreground border-warning-border hover:bg-warning-subtle/80",
    dot: "bg-warning",
    swatch: "bg-warning-subtle border-warning-border",
  },
  health: {
    label: "健康",
    block:
      "bg-success-subtle text-success-subtle-foreground border-success-border hover:bg-success-subtle/80",
    dot: "bg-success",
    swatch: "bg-success-subtle border-success-border",
  },
  social: {
    label: "交友",
    block:
      "bg-destructive-subtle text-destructive-subtle-foreground border-destructive-border hover:bg-destructive-subtle/80",
    dot: "bg-destructive",
    swatch: "bg-destructive-subtle border-destructive-border",
  },
};

/* Grid geometry */
const DAY_START = 7 * 60; // 07:00
const DAY_END = 21 * 60; // 21:00
const HOURS = Array.from(
  { length: (DAY_END - DAY_START) / 60 + 1 },
  (_, i) => 7 + i
); // 7..21
const PX_PER_MIN = 0.9; // 54px per hour
const GRID_HEIGHT = (DAY_END - DAY_START) * PX_PER_MIN;

const WEEKDAYS = ["月", "火", "水", "木", "金", "土", "日"];
const WEEKDAYS_LONG = [
  "月曜日",
  "火曜日",
  "水曜日",
  "木曜日",
  "金曜日",
  "土曜日",
  "日曜日",
];

/* ------------------------------------------------------------------ */
/* Date helpers                                                        */
/* ------------------------------------------------------------------ */

/** Monday 00:00 of the week containing `d`. */
function startOfWeek(d: Date): Date {
  const x = new Date(d.getFullYear(), d.getMonth(), d.getDate());
  const dow = (x.getDay() + 6) % 7; // Mon=0 … Sun=6
  x.setDate(x.getDate() - dow);
  return x;
}
function addDays(d: Date, n: number): Date {
  const x = new Date(d);
  x.setDate(x.getDate() + n);
  return x;
}
function sameDay(a: Date, b: Date): boolean {
  return (
    a.getFullYear() === b.getFullYear() &&
    a.getMonth() === b.getMonth() &&
    a.getDate() === b.getDate()
  );
}
function fmtTime(min: number): string {
  const h = Math.floor(min / 60);
  const m = min % 60;
  return `${h}:${m.toString().padStart(2, "0")}`;
}
function fmtRangeLabel(weekStart: Date): string {
  const end = addDays(weekStart, 6);
  const opts: Intl.DateTimeFormatOptions = { month: "long", day: "numeric" };
  const s = weekStart.toLocaleDateString("ja-JP", opts);
  const sameMonth = weekStart.getMonth() === end.getMonth();
  const e = end.toLocaleDateString(
    "ja-JP",
    sameMonth ? { day: "numeric" } : opts
  );
  return `${end.getFullYear()}年 ${s} 〜 ${e}`;
}

/* ------------------------------------------------------------------ */
/* Sample events (≥8, ≥1 overlap pair, ≥1 all-day, spread Mon–Sun)     */
/* ------------------------------------------------------------------ */

const SAMPLE_EVENTS: CalEvent[] = [
  // Monday — an overlap pair (standup + design sync overlap 9:30–10:00)
  { id: "e1", title: "朝会", dayOffset: 0, start: 9 * 60, end: 9 * 60 + 30, category: "work", location: "Zoom" },
  { id: "e2", title: "午前の集中タイム", dayOffset: 0, start: 9 * 60 + 30, end: 11 * 60, category: "focus" },
  { id: "e3", title: "デザイン定例", dayOffset: 0, start: 9 * 60 + 30, end: 10 * 60 + 30, category: "work", location: "会議室4B" },
  // Tuesday
  { id: "e4", title: "メイさんと1on1", dayOffset: 1, start: 13 * 60, end: 13 * 60 + 45, category: "work", location: "カフェ" },
  { id: "e5", title: "ジム", dayOffset: 1, start: 18 * 60, end: 19 * 60, category: "health" },
  // Wednesday — all-day + a meeting
  { id: "e6", title: "全社オフサイト", dayOffset: 2, start: 0, end: 0, allDay: true, category: "social" },
  { id: "e7", title: "サムさんとランチ", dayOffset: 2, start: 12 * 60, end: 13 * 60, category: "social", location: "ラーメン店" },
  // Thursday — another overlap pair (review overlaps interview)
  { id: "e8", title: "コードレビュー", dayOffset: 3, start: 14 * 60, end: 15 * 60 + 30, category: "work" },
  { id: "e9", title: "候補者面接", dayOffset: 3, start: 14 * 60 + 30, end: 15 * 60 + 30, category: "work", location: "Meet" },
  // Friday
  { id: "e10", title: "ディープワーク", dayOffset: 4, start: 10 * 60, end: 12 * 60, category: "focus" },
  { id: "e11", title: "チーム振り返り", dayOffset: 4, start: 16 * 60, end: 17 * 60, category: "work", location: "会議室2A" },
  // Saturday / Sunday
  { id: "e12", title: "ファーマーズマーケット", dayOffset: 5, start: 0, end: 0, allDay: true, category: "personal" },
  { id: "e13", title: "ヨガ", dayOffset: 6, start: 8 * 60, end: 9 * 60, category: "health", location: "スタジオ" },
  { id: "e14", title: "家族で夕食", dayOffset: 6, start: 18 * 60, end: 20 * 60, category: "personal", location: "自宅" },
];

/* ------------------------------------------------------------------ */
/* Overlap packing — assigns each timed event a (column, columnCount)  */
/* so overlapping events render side-by-side instead of stacked.       */
/* ------------------------------------------------------------------ */

type PackedEvent = CalEvent & { col: number; cols: number };

function packDay(events: CalEvent[]): PackedEvent[] {
  const timed = events
    .filter((e) => !e.allDay)
    .sort((a, b) => a.start - b.start || a.end - b.end);

  const result: PackedEvent[] = [];
  // Process in connected "clusters" (groups that transitively overlap).
  let i = 0;
  while (i < timed.length) {
    const cluster: CalEvent[] = [timed[i]];
    let clusterEnd = timed[i].end;
    let j = i + 1;
    while (j < timed.length && timed[j].start < clusterEnd) {
      cluster.push(timed[j]);
      clusterEnd = Math.max(clusterEnd, timed[j].end);
      j++;
    }
    // Greedy column assignment within the cluster.
    const colEnds: number[] = []; // end time per column
    const assigned: { ev: CalEvent; col: number }[] = [];
    for (const ev of cluster) {
      let col = colEnds.findIndex((end) => end <= ev.start);
      if (col === -1) {
        col = colEnds.length;
        colEnds.push(ev.end);
      } else {
        colEnds[col] = ev.end;
      }
      assigned.push({ ev, col });
    }
    const cols = colEnds.length;
    for (const a of assigned) {
      result.push({ ...a.ev, col: a.col, cols });
    }
    i = j;
  }
  return result;
}

/* ------------------------------------------------------------------ */
/* Now-line — client-only, recomputed each minute                      */
/* ------------------------------------------------------------------ */

function useNowMinutes(active: boolean): number | null {
  const [now, setNow] = React.useState<number | null>(null);
  React.useEffect(() => {
    if (!active) return;
    const tick = () => {
      const d = new Date();
      setNow(d.getHours() * 60 + d.getMinutes());
    };
    tick();
    const id = window.setInterval(tick, 60_000);
    return () => window.clearInterval(id);
  }, [active]);
  return now;
}

/* ================================================================== */
/* Event block                                                         */
/* ================================================================== */

function EventBlock({
  ev,
  onOpen,
}: {
  ev: PackedEvent;
  onOpen: (anchor: HTMLElement, ev: CalEvent) => void;
}) {
  const top = (ev.start - DAY_START) * PX_PER_MIN;
  const height = Math.max((ev.end - ev.start) * PX_PER_MIN, 22);
  const widthPct = 100 / ev.cols;
  const leftPct = ev.col * widthPct;
  const cat = CATEGORY_STYLES[ev.category];
  const timeLabel = `${fmtTime(ev.start)} – ${fmtTime(ev.end)}`;

  return (
    <button
      type="button"
      onClick={(e) => onOpen(e.currentTarget, ev)}
      // Screen reader hears: "朝会、仕事、9:00 – 9:30、Zoom"
      aria-label={`${ev.title}、${cat.label}、${timeLabel}${
        ev.location ? `、${ev.location}` : ""
      }`}
      className={`absolute overflow-hidden rounded-md border px-2 py-1 text-left text-xs leading-tight shadow-sm transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1 ${cat.block}`}
      style={{
        top,
        height,
        left: `calc(${leftPct}% + 2px)`,
        width: `calc(${widthPct}% - 4px)`,
      }}
    >
      <span className="block truncate font-semibold">{ev.title}</span>
      {height > 34 && (
        <span className="block truncate opacity-80">{fmtTime(ev.start)}</span>
      )}
    </button>
  );
}

/* ================================================================== */
/* Day column                                                          */
/* ================================================================== */

function DayColumn({
  date,
  dayOffset,
  events,
  isToday,
  nowMinutes,
  onOpenEvent,
  onCreateAt,
}: {
  date: Date;
  dayOffset: number;
  events: CalEvent[];
  isToday: boolean;
  nowMinutes: number | null;
  onOpenEvent: (anchor: HTMLElement, ev: CalEvent) => void;
  onCreateAt: (date: Date, minute: number) => void;
}) {
  const packed = React.useMemo(
    () => packDay(events.filter((e) => e.dayOffset === dayOffset)),
    [events, dayOffset]
  );
  const showNow =
    isToday && nowMinutes !== null && nowMinutes >= DAY_START && nowMinutes <= DAY_END;
  const nowTop = nowMinutes !== null ? (nowMinutes - DAY_START) * PX_PER_MIN : 0;

  return (
    <div
      className="relative flex-1 border-l border-border"
      style={{ height: GRID_HEIGHT }}
    >
      {/* Hour cells — clickable empty slots open the create dialog */}
      {HOURS.slice(0, -1).map((h) => (
        <button
          key={h}
          type="button"
          aria-label={`${WEEKDAYS_LONG[dayOffset]} ${fmtTime(
            h * 60
          )} に予定を作成`}
          onClick={() => onCreateAt(date, h * 60)}
          className="absolute left-0 w-full border-b border-border/60 hover:bg-muted/40 focus:outline-none focus-visible:bg-muted/60"
          style={{ top: (h * 60 - DAY_START) * PX_PER_MIN, height: 60 * PX_PER_MIN }}
        />
      ))}

      {/* Events */}
      {packed.map((ev) => (
        <EventBlock key={ev.id} ev={ev} onOpen={onOpenEvent} />
      ))}

      {/* Now indicator — today only, client only */}
      {showNow && (
        <div
          className="pointer-events-none absolute left-0 z-20 w-full"
          style={{ top: nowTop }}
          aria-hidden="true"
        >
          <div className="relative">
            <span className="absolute -left-1 -top-[5px] h-2.5 w-2.5 rounded-full bg-destructive" />
            <div className="h-[2px] w-full bg-destructive" />
          </div>
        </div>
      )}
    </div>
  );
}

/* ================================================================== */
/* Page                                                                */
/* ================================================================== */

type ViewMode = "day" | "week" | "month";

export default function SchedulePage() {
  const [mounted, setMounted] = React.useState(false);
  const [anchorDate, setAnchorDate] = React.useState<Date>(() =>
    startOfWeek(new Date())
  );
  const [view, setView] = React.useState<ViewMode>("week");
  const [selectedDayOffset, setSelectedDayOffset] = React.useState(0); // for day view / mobile
  const events = SAMPLE_EVENTS; // static demo data

  // Event details popover state. `anchorRect` positions a fixed PopoverAnchor
  // over the clicked event block so Radix can flip/shift the content near it.
  const [activeEvent, setActiveEvent] = React.useState<CalEvent | null>(null);
  const [popoverOpen, setPopoverOpen] = React.useState(false);
  const [anchorRect, setAnchorRect] = React.useState<{
    left: number;
    top: number;
    width: number;
    height: number;
  } | null>(null);

  // Create dialog state
  const [createOpen, setCreateOpen] = React.useState(false);
  const [createSeed, setCreateSeed] = React.useState<{
    date: Date;
    minute: number;
  } | null>(null);
  const [formTitle, setFormTitle] = React.useState("");
  const [formCategory, setFormCategory] = React.useState<Category>("work");

  React.useEffect(() => {
    setMounted(true);
    // On mount, snap day-view selection + mobile to *today* if it's in this week.
    const todayOffset = Math.round(
      (new Date(new Date().toDateString()).getTime() -
        startOfWeek(new Date()).getTime()) /
        86_400_000
    );
    if (todayOffset >= 0 && todayOffset <= 6) setSelectedDayOffset(todayOffset);
  }, []);

  const nowMinutes = useNowMinutes(mounted);
  const today = React.useMemo(() => new Date(), [mounted]); // eslint-disable-line react-hooks/exhaustive-deps

  const weekStart = anchorDate;
  const days = React.useMemo(
    () => Array.from({ length: 7 }, (_, i) => addDays(weekStart, i)),
    [weekStart]
  );

  const allDayByOffset = React.useMemo(() => {
    const map = new Map<number, CalEvent[]>();
    for (const e of events) {
      if (e.allDay) {
        const arr = map.get(e.dayOffset) ?? [];
        arr.push(e);
        map.set(e.dayOffset, arr);
      }
    }
    return map;
  }, [events]);

  /* ---- navigation ---- */
  function go(deltaWeeks: number) {
    setAnchorDate((d) => addDays(d, deltaWeeks * 7));
  }
  function goDay(delta: number) {
    // day view advances one day, wrapping the week if needed
    setSelectedDayOffset((o) => {
      const next = o + delta;
      if (next < 0) {
        setAnchorDate((d) => addDays(d, -7));
        return 6;
      }
      if (next > 6) {
        setAnchorDate((d) => addDays(d, 7));
        return 0;
      }
      return next;
    });
  }
  function goToday() {
    setAnchorDate(startOfWeek(new Date()));
    const t = Math.round(
      (new Date(new Date().toDateString()).getTime() -
        startOfWeek(new Date()).getTime()) /
        86_400_000
    );
    setSelectedDayOffset(t >= 0 && t <= 6 ? t : 0);
  }

  /* ---- event open (popover) ---- */
  function openEvent(anchor: HTMLElement, ev: CalEvent) {
    const r = anchor.getBoundingClientRect();
    setAnchorRect({ left: r.left, top: r.top, width: r.width, height: r.height });
    setActiveEvent(ev);
    setPopoverOpen(true);
  }

  /* ---- empty slot create ---- */
  function createAt(date: Date, minute: number) {
    setCreateSeed({ date, minute });
    setFormTitle("");
    setFormCategory("work");
    setCreateOpen(true);
  }

  const isThisWeekToday = (d: Date) => mounted && sameDay(d, today);

  /* ---- which day offsets to render (responsive / view) ---- */
  // Desktop week view = 7 columns; day view (or any view on mobile) = 1 column.

  return (
    <TooltipProvider delayDuration={200}>
      <main className="mx-auto flex w-full max-w-[1200px] flex-col gap-4 p-4 sm:p-6">
        {/* The single page <h1> */}
        <header className="flex flex-col gap-1">
          <h1 className="flex items-center gap-2 text-2xl font-bold tracking-tight">
            <Icon icon={IconCalendarEvent} size="lg" aria-hidden="true" />
            スケジュール
          </h1>
          <p className="text-sm text-muted-foreground">
            @gunjo/ui のプリミティブで組み上げた週表示スケジューラー。
          </p>
        </header>

        {/* Toolbar */}
        <Card className="flex-row flex-wrap items-center justify-between gap-3 p-3">
          <div className="flex items-center gap-2">
            <div className="flex items-center gap-1">
              <Button
                variant="outline"
                size="icon"
                aria-label={view === "day" ? "前の日" : "前の週"}
                onClick={() => (view === "day" ? goDay(-1) : go(-1))}
              >
                <Icon icon={IconChevronLeft} size="sm" aria-hidden="true" />
              </Button>
              <Button variant="outline" size="sm" onClick={goToday}>
                今日
              </Button>
              <Button
                variant="outline"
                size="icon"
                aria-label={view === "day" ? "次の日" : "次の週"}
                onClick={() => (view === "day" ? goDay(1) : go(1))}
              >
                <Icon icon={IconChevronRight} size="sm" aria-hidden="true" />
              </Button>
            </div>
            <h2 className="ml-1 text-base font-semibold sm:text-lg" aria-live="polite">
              {view === "day"
                ? days[selectedDayOffset].toLocaleDateString("ja-JP", {
                    year: "numeric",
                    month: "long",
                    day: "numeric",
                    weekday: "long",
                  })
                : fmtRangeLabel(weekStart)}
            </h2>
          </div>

          <div className="flex items-center gap-2">
            <ToggleGroup
              type="single"
              value={view}
              onValueChange={(v) => v && setView(v as ViewMode)}
              variant="outline"
              size="sm"
              aria-label="カレンダーの表示形式"
              className="hidden sm:flex"
            >
              <ToggleGroupItem value="day">日</ToggleGroupItem>
              <ToggleGroupItem value="week">週</ToggleGroupItem>
              <ToggleGroupItem value="month">月</ToggleGroupItem>
            </ToggleGroup>
            <Button
              variant="primary"
              size="sm"
              onClick={() => createAt(days[selectedDayOffset] ?? days[0], 9 * 60)}
            >
              <Icon icon={IconPlus} size="sm" aria-hidden="true" />
              <span className="ml-1">予定を追加</span>
            </Button>
          </div>
        </Card>

        {/* Body: mini-calendar (desktop) + main view */}
        <div className="flex gap-4">
          {/* Mini calendar — date jump (desktop, week/day views) */}
          {view !== "month" && (
            <aside className="hidden shrink-0 lg:block">
              <Card className="p-3">
                <Calendar
                  mode="single"
                  locale={undefined}
                  selected={days[selectedDayOffset]}
                  month={weekStart}
                  showHolidays={false}
                  showWeekendStyle={false}
                  onSelect={(d) => {
                    if (!d) return;
                    setAnchorDate(startOfWeek(d));
                    const off = (d.getDay() + 6) % 7;
                    setSelectedDayOffset(off);
                  }}
                />
              </Card>
            </aside>
          )}

          <div className="min-w-0 flex-1">
            {view === "month" ? (
              <MonthView
                weekStart={weekStart}
                events={events}
                today={isThisWeekToday}
                onPickDay={(off) => {
                  setSelectedDayOffset(off);
                  setView("day");
                }}
              />
            ) : (
              <>
                {/* DESKTOP / TABLET: full week (week view) OR single day (day view) */}
                <div className={view === "day" ? "block" : "hidden sm:block"}>
                  <WeekGrid
                    days={view === "day" ? [days[selectedDayOffset]] : days}
                    offsets={
                      view === "day" ? [selectedDayOffset] : [0, 1, 2, 3, 4, 5, 6]
                    }
                    events={events}
                    allDayByOffset={allDayByOffset}
                    isToday={isThisWeekToday}
                    nowMinutes={nowMinutes}
                    onOpenEvent={openEvent}
                    onCreateAt={createAt}
                  />
                </div>

                {/* MOBILE (week view only): collapse to a single-day grid; */}
                {/* day view already renders one column above. */}
                {view === "week" && (
                  <div className="block sm:hidden">
                    <div className="mb-2 flex items-center justify-between">
                      <Button
                        variant="ghost"
                        size="sm"
                        aria-label="前の日"
                        onClick={() => goDay(-1)}
                      >
                        <Icon icon={IconChevronLeft} size="sm" aria-hidden="true" />
                      </Button>
                      <span className="text-sm font-medium">
                        {days[selectedDayOffset].toLocaleDateString("ja-JP", {
                          month: "long",
                          day: "numeric",
                          weekday: "long",
                        })}
                      </span>
                      <Button
                        variant="ghost"
                        size="sm"
                        aria-label="次の日"
                        onClick={() => goDay(1)}
                      >
                        <Icon icon={IconChevronRight} size="sm" aria-hidden="true" />
                      </Button>
                    </div>
                    <WeekGrid
                      days={[days[selectedDayOffset]]}
                      offsets={[selectedDayOffset]}
                      events={events}
                      allDayByOffset={allDayByOffset}
                      isToday={isThisWeekToday}
                      nowMinutes={nowMinutes}
                      onOpenEvent={openEvent}
                      onCreateAt={createAt}
                    />
                  </div>
                )}
              </>
            )}

            {/* Legend */}
            <div className="mt-4 flex flex-wrap items-center gap-x-4 gap-y-2">
              {(Object.keys(CATEGORY_STYLES) as Category[]).map((c) => (
                <span key={c} className="flex items-center gap-1.5 text-xs text-muted-foreground">
                  <span
                    className={`h-3 w-3 rounded-full ${CATEGORY_STYLES[c].dot}`}
                    aria-hidden="true"
                  />
                  {CATEGORY_STYLES[c].label}
                </span>
              ))}
            </div>
          </div>
        </div>

        {/* Event-details Popover, anchored to a fixed box over the clicked block */}
        <Popover open={popoverOpen} onOpenChange={setPopoverOpen}>
          <PopoverAnchor asChild>
            <span
              aria-hidden="true"
              className="pointer-events-none"
              style={{
                position: "fixed",
                left: anchorRect?.left ?? 0,
                top: anchorRect?.top ?? 0,
                width: anchorRect?.width ?? 0,
                height: anchorRect?.height ?? 0,
              }}
            />
          </PopoverAnchor>
          <PopoverContent
            align="start"
            side="right"
            className="w-80"
            onOpenAutoFocus={(e) => e.preventDefault()}
          >
            {activeEvent && (
              <EventDetails ev={activeEvent} date={days[activeEvent.dayOffset]} />
            )}
          </PopoverContent>
        </Popover>

        {/* Create-event Dialog */}
        <Dialog open={createOpen} onOpenChange={setCreateOpen}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>予定を追加</DialogTitle>
              <DialogDescription>
                {createSeed
                  ? `${createSeed.date.toLocaleDateString("ja-JP", {
                      month: "long",
                      day: "numeric",
                      weekday: "long",
                    })} ${fmtTime(createSeed.minute)}`
                  : "この週に予定を追加します。"}
              </DialogDescription>
            </DialogHeader>

            <form
              onSubmit={(e) => {
                e.preventDefault();
                // Demo: we don't mutate the static dataset; just close.
                setCreateOpen(false);
              }}
              className="flex flex-col gap-4"
            >
              <div className="flex flex-col gap-1.5">
                <label htmlFor="ev-title" className="text-sm font-medium">
                  タイトル
                </label>
                <input
                  id="ev-title"
                  value={formTitle}
                  onChange={(e) => setFormTitle(e.target.value)}
                  placeholder="予定のタイトル"
                  autoFocus
                  className="h-9 rounded-lg border border-input bg-transparent px-3 text-sm focus:outline-none focus:ring-1 focus:ring-ring"
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <label htmlFor="ev-cat" className="text-sm font-medium">
                  カテゴリー
                </label>
                <Select
                  id="ev-cat"
                  value={formCategory}
                  onChange={(e) => setFormCategory(e.target.value as Category)}
                >
                  {(Object.keys(CATEGORY_STYLES) as Category[]).map((c) => (
                    <option key={c} value={c}>
                      {CATEGORY_STYLES[c].label}
                    </option>
                  ))}
                </Select>
              </div>

              <DialogFooter>
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  onClick={() => setCreateOpen(false)}
                >
                  キャンセル
                </Button>
                <Button type="submit" variant="primary" size="sm">
                  予定を作成
                </Button>
              </DialogFooter>
            </form>
          </DialogContent>
        </Dialog>
      </main>
    </TooltipProvider>
  );
}

/* ================================================================== */
/* Week grid (time axis + all-day lane + day columns)                  */
/* ================================================================== */

function WeekGrid({
  days,
  offsets,
  events,
  allDayByOffset,
  isToday,
  nowMinutes,
  onOpenEvent,
  onCreateAt,
}: {
  days: Date[];
  offsets: number[];
  events: CalEvent[];
  allDayByOffset: Map<number, CalEvent[]>;
  isToday: (d: Date) => boolean;
  nowMinutes: number | null;
  onOpenEvent: (anchor: HTMLElement, ev: CalEvent) => void;
  onCreateAt: (date: Date, minute: number) => void;
}) {
  const hasAnyAllDay = offsets.some((o) => (allDayByOffset.get(o)?.length ?? 0) > 0);

  return (
    <Card className="overflow-hidden p-0">
      {/* Header row: day names */}
      <div className="flex border-b border-border">
        <div className="w-14 shrink-0 sm:w-16" aria-hidden="true" />
        {days.map((d, i) => {
          const off = offsets[i];
          const todayCol = isToday(d);
          return (
            <div
              key={off}
              className={`flex-1 border-l border-border px-1 py-2 text-center ${
                todayCol ? "bg-primary-subtle" : ""
              }`}
            >
              <div className="text-[11px] uppercase tracking-wide text-muted-foreground">
                {WEEKDAYS[off]}
              </div>
              <div className="flex items-center justify-center gap-1">
                <span
                  className={`inline-flex h-7 w-7 items-center justify-center rounded-full text-sm font-semibold ${
                    todayCol ? "bg-primary text-primary-foreground" : ""
                  }`}
                >
                  {d.getDate()}
                </span>
                {todayCol && (
                  <span className="sr-only">（今日）</span>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* All-day lane */}
      {hasAnyAllDay && (
        <div className="flex border-b border-border bg-muted/20">
          <div className="flex w-14 shrink-0 items-center justify-end pr-2 text-[10px] uppercase text-muted-foreground sm:w-16">
            終日
          </div>
          {offsets.map((off) => {
            const items = allDayByOffset.get(off) ?? [];
            return (
              <div key={off} className="flex-1 space-y-1 border-l border-border p-1">
                {items.map((ev) => {
                  const cat = CATEGORY_STYLES[ev.category];
                  return (
                    <button
                      key={ev.id}
                      type="button"
                      onClick={(e) => onOpenEvent(e.currentTarget, ev)}
                      aria-label={`${ev.title}、${cat.label}、終日`}
                      className={`block w-full truncate rounded border px-1.5 py-0.5 text-left text-xs font-medium focus:outline-none focus-visible:ring-2 focus-visible:ring-ring ${cat.block}`}
                    >
                      {ev.title}
                    </button>
                  );
                })}
              </div>
            );
          })}
        </div>
      )}

      {/* Scrollable time grid */}
      <ScrollArea className="max-h-[60vh]" viewportClassName="overscroll-contain">
        <div className="flex" style={{ height: GRID_HEIGHT }}>
          {/* Time axis */}
          <div className="relative w-14 shrink-0 sm:w-16" aria-hidden="true">
            {HOURS.map((h) => (
              <div
                key={h}
                className="absolute right-2 -translate-y-1/2 text-[11px] tabular-nums text-muted-foreground"
                style={{ top: (h * 60 - DAY_START) * PX_PER_MIN }}
              >
                {fmtTime(h * 60).replace(":00", "")}
              </div>
            ))}
          </div>

          {/* Day columns */}
          {days.map((d, i) => (
            <DayColumn
              key={offsets[i]}
              date={d}
              dayOffset={offsets[i]}
              events={events}
              isToday={isToday(d)}
              nowMinutes={nowMinutes}
              onOpenEvent={onOpenEvent}
              onCreateAt={onCreateAt}
            />
          ))}
        </div>
      </ScrollArea>
    </Card>
  );
}

/* ================================================================== */
/* Event details (inside Popover)                                      */
/* ================================================================== */

function EventDetails({ ev, date }: { ev: CalEvent; date: Date }) {
  const cat = CATEGORY_STYLES[ev.category];
  const dateLabel = date.toLocaleDateString("ja-JP", {
    month: "long",
    day: "numeric",
    weekday: "long",
  });
  return (
    <div className="flex flex-col gap-2">
      <div className="flex items-start gap-2">
        <span className={`mt-1 h-3 w-3 shrink-0 rounded-full ${cat.dot}`} aria-hidden="true" />
        <div className="min-w-0">
          <h3 className="text-sm font-semibold leading-snug">{ev.title}</h3>
          <Badge variant="outline" className="mt-1">
            {cat.label}
          </Badge>
        </div>
      </div>
      <Separator className="my-1" />
      <dl className="flex flex-col gap-1.5 text-sm">
        <div className="flex items-center gap-2 text-muted-foreground">
          <Icon icon={IconClock} size="sm" aria-hidden="true" />
          <span>
            {ev.allDay
              ? `${dateLabel} ・ 終日`
              : `${dateLabel} ・ ${fmtTime(ev.start)} 〜 ${fmtTime(ev.end)}`}
          </span>
        </div>
        {ev.location && (
          <div className="flex items-center gap-2 text-muted-foreground">
            <Icon icon={IconMapPin} size="sm" aria-hidden="true" />
            <span>{ev.location}</span>
          </div>
        )}
      </dl>
    </div>
  );
}

/* ================================================================== */
/* Month view (lightweight; clicking a day jumps to day view)          */
/* ================================================================== */

function MonthView({
  weekStart,
  events,
  today,
  onPickDay,
}: {
  weekStart: Date;
  events: CalEvent[];
  today: (d: Date) => boolean;
  onPickDay: (offset: number) => void;
}) {
  // Build the month grid around the anchor week's month.
  const anchor = weekStart;
  const monthStart = new Date(anchor.getFullYear(), anchor.getMonth(), 1);
  const gridStart = startOfWeek(monthStart);
  const cells = Array.from({ length: 42 }, (_, i) => addDays(gridStart, i));

  // Map events onto absolute calendar dates (relative to this page's week origin).
  const weekOrigin = weekStart; // dayOffset 0 == weekStart
  const eventsByDate = new Map<string, CalEvent[]>();
  for (const e of events) {
    const d = addDays(weekOrigin, e.dayOffset);
    const key = d.toDateString();
    const arr = eventsByDate.get(key) ?? [];
    arr.push(e);
    eventsByDate.set(key, arr);
  }

  return (
    <Card className="p-2">
      <div className="grid grid-cols-7 border-b border-border pb-1 text-center text-[11px] uppercase text-muted-foreground">
        {WEEKDAYS.map((d) => (
          <div key={d}>{d}</div>
        ))}
      </div>
      <div className="grid grid-cols-7">
        {cells.map((d, i) => {
          const inMonth = d.getMonth() === anchor.getMonth();
          const dayEvents = eventsByDate.get(d.toDateString()) ?? [];
          const isTodayCell = today(d);
          // offset relative to the visible week origin, only meaningful 0..6
          const off = Math.round((d.getTime() - weekOrigin.getTime()) / 86_400_000);
          const clickable = off >= 0 && off <= 6;
          return (
            <button
              key={i}
              type="button"
              disabled={!clickable}
              onClick={() => clickable && onPickDay(off)}
              aria-label={`${d.toLocaleDateString("ja-JP", {
                month: "long",
                day: "numeric",
                weekday: "long",
              })}${dayEvents.length ? `、予定${dayEvents.length}件` : ""}`}
              className={`min-h-[88px] border-b border-l border-border p-1 text-left align-top transition-colors first:border-l-0 disabled:cursor-default ${
                clickable ? "hover:bg-muted/40" : ""
              } ${inMonth ? "" : "bg-muted/20 text-muted-foreground"}`}
            >
              <span
                className={`inline-flex h-6 w-6 items-center justify-center rounded-full text-xs font-semibold ${
                  isTodayCell ? "bg-primary text-primary-foreground" : ""
                }`}
              >
                {d.getDate()}
              </span>
              {isTodayCell && <span className="sr-only">（今日）</span>}
              <div className="mt-1 space-y-0.5">
                {dayEvents.slice(0, 3).map((ev) => (
                  <div
                    key={ev.id}
                    className="flex items-center gap-1 truncate text-[10px]"
                  >
                    <span
                      className={`h-1.5 w-1.5 shrink-0 rounded-full ${
                        CATEGORY_STYLES[ev.category].dot
                      }`}
                      aria-hidden="true"
                    />
                    <span className="truncate">{ev.title}</span>
                  </div>
                ))}
                {dayEvents.length > 3 && (
                  <div className="text-[10px] text-muted-foreground">
                    他{dayEvents.length - 3}件
                  </div>
                )}
              </div>
            </button>
          );
        })}
      </div>
    </Card>
  );
}
